import { Injectable } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http'
import { JwtHelperService } from '@auth0/angular-jwt';
import { HttpHeaders } from '@angular/common/http';
import { environment } from '../../../../environments/environment';
import decode from 'jwt-decode';
import { Router } from '@angular/router';
import { MatSnackBar } from '@angular/material/snack-bar';

@Injectable()
export class AuthService {
    serverAddress = environment.url;
    constructor(
        public jwtHelper: JwtHelperService,
        private http: HttpClient,
        public router: Router,
        private _snackBar: MatSnackBar,
    ) { }

    // === Token Management ===
    setToken(token: string): void {
        localStorage.setItem('token', token);
    }

    getToken(): string | null {
        return localStorage.getItem('token');
    }

    clearToken(): void {
        localStorage.removeItem('token');
    }

    // === Headers ===
    getAuthHeaders(): HttpHeaders {
        const token = this.getToken();
        return new HttpHeaders().set('Authorization', token || '');
    }

    setUserAuth(token) {
        token = localStorage.getItem("token")
        const headers = new HttpHeaders()
            .set('Authorization', token)
        return headers
    }

    async isAuthenticated() {
        const token = localStorage.getItem('token');
        // Check whether the token is expired and return
        // true or false
        let isvalid = await this.verifyToken(token)

        return isvalid;
    }
    async verifyToken(token): Promise<boolean> {
        let isvalid = <boolean>await new Promise((resolve, reject) => {
            this.http.get(this.serverAddress + `/verifyToken`, { headers: this.setUserAuth(token) }).subscribe((data: any) => {
                if (data.status == "success" && !this.jwtHelper.isTokenExpired(token)) {
                    resolve(true);
                }
                else {
                    resolve(false);
                }
            })
        })
        return isvalid;
    }

    async getUserFromToken(): Promise<boolean> {
        const token = localStorage.getItem('token');
        if (token) {
            try {
                return decode(token);
            } catch {
                return null;
            }
        }
        return null;
    }

    // === Logout ===
    logout(redirectUrl: string = '/login', message?: string): void {
        this.clearToken();
        if (message) {
            this.showLogoutNotification(message);
        }
        this.router.navigate([redirectUrl]);
    }

    private showLogoutNotification(message: string): void {
        this._snackBar.open(message, 'OK', {
            duration: 5000, // 5 seconds
            panelClass: ['logout-snackbar'], // Optional custom styling
            horizontalPosition: 'center',
            verticalPosition: 'top'
        });
    }
}

