}import { Injectable } from '@angular/core';
import { Router, ActivatedRouteSnapshot } from '@angular/router';
import { AuthService } from './auth.service';
import decode from 'jwt-decode';
import { itemService } from 'src/app/helpers/services/main.service';
@Injectable()
export class RoleGuardService  {
    constructor(public auth: AuthService, public router: Router, private itemService: itemService) { }
    async canActivate(route: ActivatedRouteSnapshot) {
        // this will be passed from the route config on the data property
        const roles: string | string[] = route.data.role; // Can be a string or an array of strings
    
        const token = localStorage.getItem('token');
        // decode the token to get its payload
        const tokenPayload = <any>decode(token);
        const userRole = tokenPayload.role;
      
        if (await this.auth.isAuthenticated()) {
            // Check if user role matches any of the allowed roles
            if (Array.isArray(roles) ? roles.includes(userRole) : roles === userRole) {
                return true;
            } else {
                this.router.navigate(['pages/error-401']);
                return false;
            }
        } else {
            this.router.navigate(['/login']);
        }
    }
    async isAuth(role: any) {
        const token = localStorage.getItem('token');
        // decode the token to get its payload
        const tokenPayload = <any>decode(token);
        if (await this.auth.isAuthenticated()) {
            if (tokenPayload.role != role) {
                return false;
            } else {
                return true;
            }
        } else {
            this.router.navigate(['/login']);
        }
    }
    getRole(){
        const token = localStorage.getItem('token');
        // decode the token to get its payload
        const tokenPayload = <any>decode(token);
        if ( this.auth.isAuthenticated()) {
           return tokenPayload.role
        }
    }
    getUserId(){
        const token = localStorage.getItem('token');
        // decode the token to get its payload
        const tokenPayload = <any>decode(token);
        return tokenPayload.user_id;
    }
}import { Injectable, NgZone, OnDestroy } from '@angular/core';
import { MatSnackBar } from '@angular/material/snack-bar';
import { AuthService } from './auth.service';
import { ConfigService } from 'src/app/helpers/services/config.service';
import { MatDialog } from '@angular/material/dialog'; 

@Injectable({ providedIn: 'root' })
export class IdleTimeoutService implements OnDestroy {
  private timeoutId: any;
  private warningTimeoutId: any;
  private warningSnackbarRef: any;
  private idleTime:number;
  private readonly warningTime = 5 * 60 * 1000; // 5 minutes warning
  private eventListeners: { [key: string]: EventListener } = {};

  constructor(
    private zone: NgZone,
    private authService: AuthService,
    private configService: ConfigService,
    private snackBar: MatSnackBar,  
    private dialog: MatDialog

  ) { }

  async startWatching(): Promise<void> {
    await this.setIdleTimeForUser();
    this.resetTimers();
    this.setupEventListeners();
   
  }

  private async setIdleTimeForUser(): Promise<void> {
    const user = await this.authService.getUserFromToken() as any
    const excludedUserIds = this.configService.get('excludedUserIds') as number[];

    const isAdmin = excludedUserIds?.includes(user.user_id);

    this.idleTime = isAdmin
      ? 12 * 60 * 60 * 1000 // 12 hours for admins
      : 2 * 60 * 60 * 1000; // 2 hours for others
  }

  private setupEventListeners(): void {
    // Clear existing listeners first
    this.removeEventListeners();

    const events = [
      'pointermove',
      'pointerdown',
      'mousemove',
      'mousedown',
      'click',
      'wheel',
      'scroll',
      'keydown',
      'contextmenu'
    ]

    events.forEach(evt => {
      const listener = () => {
        this.zone.runOutsideAngular(() => {
          this.resetTimers();
        });
      };
      this.eventListeners[evt] = listener;
      window.addEventListener(evt, listener, { passive: true, capture: true });
    });
  }

  private removeEventListeners(): void {
    Object.entries(this.eventListeners).forEach(([event, listener]) => {
      window.removeEventListener(event, listener, { capture: true });
    });
    this.eventListeners = {};
  }

  private resetTimers(): void {
    this.clearTimers();
    this.dismissWarning();

    // Set warning timer
    this.warningTimeoutId = setTimeout(() => {
      this.zone.run(() => this.showTimeoutWarning());
    }, this.idleTime - this.warningTime);

    // Set logout timer
    this.timeoutId = setTimeout(() => {
      this.zone.run(() => {
        this.dismissWarning(); // Clear warning before logout
        this.dialog.closeAll(); // ✅ Close all open Angular Material dialogs
        this.authService.logout('/login', 'You were automatically logged out due to inactivity');
      });
    }, this.idleTime);
  }

  private showTimeoutWarning(): void {
    // Clear any existing warning
    this.dismissWarning();

    const minutesLeft = Math.ceil(this.warningTime / 60000);
    this.warningSnackbarRef = this.snackBar.open(
      `You'll be logged out in ${minutesLeft} minutes due to inactivity`,
      'STAY LOGGED IN',
      {
        duration: this.warningTime,
        panelClass: ['warning-snackbar'],
        horizontalPosition: 'center',
        verticalPosition: 'top'
      }
    );

    this.warningSnackbarRef.onAction().subscribe(() => {
      this.resetTimers();
    });
  }

  private dismissWarning(): void {
    if (this.warningSnackbarRef) {
      this.warningSnackbarRef.dismiss();
      this.warningSnackbarRef = null;
    }
  }

  private clearTimers(): void {
    clearTimeout(this.timeoutId);
    clearTimeout(this.warningTimeoutId);
  }

  stopWatching(): void {
    this.clearTimers();
    this.dismissWarning();
    this.removeEventListeners();
  }

  ngOnDestroy(): void {
    this.stopWatching();
  }
}export function shouldShowLoginFallbackError(err: any): boolean {
  if (!err) return true;

  // Angular HttpErrorResponse instances have a numeric status. The global HTTP
  // interceptor already shows the specific backend/network message for those.
  if (typeof err.status === 'number') return false;

  const code = err.errorCode || err.message;
  return code !== 'user_cancelled';
}

import { Injectable } from '@angular/core';
import { HttpRequest, HttpHandler, HttpEvent, HttpInterceptor, HttpErrorResponse } from '@angular/common/http';
import { Observable, throwError } from 'rxjs';
import { catchError } from 'rxjs/operators';
import { MatSnackBar } from '@angular/material/snack-bar';
import { getErrorMessage } from './api-error';

@Injectable()
export class HttpErrorInterceptor implements HttpInterceptor {
  constructor(private snackBar: MatSnackBar) {}

  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
    return next.handle(req).pipe(
      catchError((err: HttpErrorResponse) => {
        const msg = getErrorMessage(err, req.url);
        console.error('[HTTP Error]', err.status, req.url, err);
        this.snackBar.open(msg, 'Close', {
          duration: err?.error?.type === 'user' ? 5000 : 8000,
          panelClass: err?.error?.type === 'user' ? ['warn-snackbar'] : ['error-snackbar'],
        });
        return throwError(() => err);
      })
    );
  }
}
import { HttpEvent, HttpInterceptor, HttpHandler, HttpRequest, HttpResponse, HttpErrorResponse } from '@angular/common/http';
import { Observable, throwError } from 'rxjs';
import { retry, catchError } from 'rxjs/operators';

export class HttpErrorInterceptor implements HttpInterceptor {

    intercept(request: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {

        return next.handle(request)
            .pipe(
                retry(1),
                catchError((error: HttpErrorResponse) => {

                    let errorMessage = '';
                    if (error.error instanceof ErrorEvent) {
                        // client-side error
                        // errorMessage = `Error: ${error.error.message}`;
                    } else {
                        // server-side error
                        //errorMessage = `Error Code: ${error.status} \nMessage: ${error.message}`;
                        if (error.status == 401) {
                            window.location.replace('/pages/error-401');
                        } else if (error.status == 403) {
                            localStorage.removeItem('token');
                            window.location.replace('/login');
                        }
                    }
                    return throwError(errorMessage);

                })
            )
    }
}import { Injectable } from '@angular/core';
import { HttpRequest, HttpHandler, HttpEvent, HttpInterceptor, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable()
export class UserAuthInterceptor implements HttpInterceptor {

  constructor() {}

  intercept(request: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
    if (!request || !(request as any).headers) {
      return next.handle(request);
    }

    const token = localStorage.getItem('token');

    const authRequest = token
      ? request.clone({
          setHeaders: {
            Authorization: token
          }
        })
      : request;

    return next.handle(authRequest);
  }
}
import { Injectable } from '@angular/core';
import {
  HttpInterceptor,
  HttpRequest,
  HttpHandler,
  HttpEvent
} from '@angular/common/http';
import { Observable } from 'rxjs';
import { finalize } from 'rxjs/operators';
import { LoaderService } from '../services/loader.service';

/**
 * Loader interceptor - DISABLED by default.
 * 
 * The loader will only show for requests with header 'X-Enable-Loader: true'.
 * Services should add this header when they want to show the loader.
 * 
 * Example in service:
 * { headers: new HttpHeaders().set('X-Enable-Loader', 'true') }
 */
@Injectable({
  providedIn: 'root'
})
export class LoaderInterceptor implements HttpInterceptor {
  private readonly enableHeader = 'X-Enable-Loader';

  constructor(private readonly loaderService: LoaderService) {}

  intercept(request: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
    let shouldEnable = false;
    try {
      shouldEnable = !!(request?.headers?.has?.(this.enableHeader));
    } catch {
      shouldEnable = false;
    }

    const cleanedRequest = shouldEnable && request?.headers
      ? request.clone({ headers: request.headers.delete(this.enableHeader) })
      : request;

    if (shouldEnable) {
      this.loaderService.increment();
    }

    return next.handle(cleanedRequest).pipe(
      finalize(() => {
        if (shouldEnable) {
          this.loaderService.decrement();
        }
      })
    );
  }
}

