    if (res?.allowed === true) {
      return true;
    }

    snackBar?.open(res?.message || RFQ_COPY_BLOCKED_MESSAGE, 'Close', {
      duration: 6000,
    });
    return false;
  } catch {
    snackBar?.open('Unable to verify copy eligibility.', 'Close');
    return false;
  }
}
