/**
 * Extract a user-facing message from an Angular HttpErrorResponse.
 *
 * - Backend user errors (400): show the message as-is
 * - Backend system errors (500): show stable code + generic advice
 * - Network / unknown: generic message
 */
export function getErrorMessage(err: any, requestUrl?: string): string {
  if (!err) return 'An unexpected error occurred.';

  // Angular HttpErrorResponse
  const body = err?.error;
  if (body?.type === 'user' && body?.message) {
    return body.message;
  }
  if (body?.type === 'system' && body?.code) {
    const operation = describeRequest(requestUrl);
    const detail = formatTechnicalDetail(body.message);
    return `${operation} failed (${body.code}).${detail} Please contact support if this persists.`;
  }

  // HTTP status codes without structured body
  const operation = describeRequest(requestUrl);
  if (err?.status === 0) return `Cannot reach the Designflow server while trying to complete ${operation}. Check your connection, VPN/proxy, or regional network access, then try again. Technical details: browser reported HTTP status 0; URL: ${requestUrl || 'unknown'}.`;
  if (err?.status === 401) return `${operation} was rejected because your session is invalid or expired. Please log in again. Technical details: HTTP 401; URL: ${requestUrl || 'unknown'}.`;
  if (err?.status === 403) return `${operation} was blocked because your account does not have permission for this request. Technical details: HTTP 403; URL: ${requestUrl || 'unknown'}.`;
  if (err?.status === 404) return `${operation} could not find the requested resource. Technical details: HTTP 404; URL: ${requestUrl || 'unknown'}.`;
  if (err?.status === 503) return 'The server is temporarily unavailable (503). This usually resolves in a few seconds — please try again. Contact support if it persists.';
  if (err?.status >= 500) {
    // Include any message the server sent back so it's easier to diagnose
    const serverDetail = err?.error?.message || err?.error?.error || err?.error || '';
    const detail = typeof serverDetail === 'string' && serverDetail
      ? ` — ${serverDetail}`
      : '';
    return `Server error (${err.status})${detail}. Please contact support if this persists.`;
  }

  // Fall back to whatever the error says
  return err?.message || err?.error?.message || 'An unexpected error occurred.';
}

function describeRequest(requestUrl?: string): string {
  if (!requestUrl) return 'Request';

  const path = requestUrl.split('?')[0].split('/').filter(Boolean).pop();
  if (!path) return 'Request';

  return path
    .replace(/([a-z])([A-Z])/g, '$1 $2')
    .replace(/[-_]+/g, ' ')
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function formatTechnicalDetail(message?: string): string {
  if (!message) return '';
  return ` Technical details: ${message}.`;
}

