    if (token) {
      try {
        const res: any = await this.itemService.verifySingleUseToken({ token: token }).toPromise();
        if (res.status == true) {
          localStorage.setItem('token', res.token);
          let isValid = await this.authGuard.canActivate();
          if (isValid) {
            let rfqItem_priceCode = href[href.length - 2];
            let hightlight = href[href.length - 1];
