                      });
                    });
                  }
                });
              });
            } else {
              let url = `/apps/filterd_standardized/${href[href.length - 2]}`;
              this.router.navigate([url]);
            }
          } else {
            this.router.navigate(['/login']);
          }
        } else {
          this.router.navigate(['/login']);
        }
      } catch (err) {
        console.error('[singleUseTokenComponent] verifySingleUseToken failed:', err);
        this.router.navigate(['/login']);
      }
    } else {
      this.router.navigate(['/login']);
    }
  }

}

