          fetch(signedUrl, putConfig)
            .then(output => {
              const body = {
                flag: 'comment-create-edit',
                item_num_id_fk: itemId,
                attachment_type: contentType,
                attachment_display_name: contentType.split("/")[0],
                fileName,
                comment_id: commentId
              };
